					import java.util.ArrayList;
					import java.util.Iterator;
					import java.util.List;
					import sailpoint.api.ObjectUtil;
					import sailpoint.api.SailPointContext;
					import sailpoint.object.Identity;
					import sailpoint.object.QueryOptions;
					import sailpoint.object.Filter;
					import sailpoint.tools.Util;
                                
					List workGroupsList = new ArrayList();
					List workGroupsOwnerList = new ArrayList();
					Identity userIdentity = context.getObjectByName(Identity.class,launcher);
					Identity workGroupOwner = new Identity();
					workGroupsList = userIdentity.getWorkgroups();
					String workGroupName,workGroupOwnerName,noWorkGrpsMsg="No owner workgroups Found";
					int workGroupsCount,workGroupsOwnerCnt;	
					workGroupsCount = workGroupsList.size();
					log.trace("User-"+launcher+"-is member of-"+workGroupsCount+"-workgroups");
					Filter wkGrpFilter = Filter.eq("workgroup", true);
					Filter ownerFilter = ObjectUtil.getOwnerFilterForIdentity(userIdentity);
					QueryOptions ops = new QueryOptions();
					ops.addFilter(wkGrpFilter);
					ops.addFilter(ownerFilter);
					ops.setDistinct(true);
					Iterator it = context.search(Identity.class, ops, "name");
					if(it != null){
						while (it.hasNext()) {
							ownerName = it.next()[0];
							log.trace("Owner Workgroup Name->"+ownerName);
							workGroupsOwnerList.add(ownerName);
							workGroupsOwnerCnt++;
						}	
					} 
					Util.flushIterator(it);
					log.trace("User-"+launcher+"-is owner of-"+workGroupsOwnerCnt+"-workgroups");
					if(workGroupsOwnerCnt >0){
						workGroupsOwnerList;
					}	
					else{
						workGroupsOwnerList.add(noWorkGrpsMsg);
					 }	
					return workGroupsOwnerList;

 
				import sailpoint.api.ObjectUtil;
			  	import sailpoint.api.SailPointContext;
			  	import sailpoint.object.Identity;
                
                List workGroupExistingMembers = new ArrayList();
				Identity workGroup = context.getObjectByName(Identity.class,workgroupName);
				if(workGroup!=null){
					Iterator wgMembers = ObjectUtil.getWorkgroupMembers(context, workGroup, null);
					while (wgMembers.hasNext()){
						Object[] object = (Object[]) wgMembers.next();
						Identity member = (Identity) object[0];
						workGroupExistingMembers.add(member.getId());
					}			
				}	 
				//log.error("Existing Users In The Workgroup-"+workGroupExistingMembers);      
				return workGroupExistingMembers;

 
			  import java.util.ArrayList;
			  import java.util.Iterator;
			  import java.util.List;
			  import sailpoint.api.ObjectUtil;
			  import sailpoint.api.SailPointContext;
			  import sailpoint.object.Identity;

			  List members = new ArrayList();
			  log.trace("Selected workgroup name-"+workgroupName);
			  if (workgroupName != null) {
				Identity workGroup = context.getObjectByName(Identity.class,workgroupName);
				if(workGroup!=null){
					Iterator wgMembers = ObjectUtil.getWorkgroupMembers(context, workGroup, null);
			  		log.trace("wgMembers-"+wgMembers);
			  		while (wgMembers.hasNext()) {
						Object[] object = (Object[]) wgMembers.next();
						Identity member = (Identity) object[0];
						members.add(member.getId());
			  		}	
					return members;
			  	} 
				else{
					return workgroupName;
			 	}
			  }

        import java.util.ArrayList;
        import java.util.Iterator;
        import java.util.List;
        import sailpoint.api.ObjectUtil;
        import sailpoint.api.SailPointContext;
        import sailpoint.object.Identity;
		import sailpoint.object.AuditEvent;
		
        List addedMembers = new ArrayList();
		List removedMembers = new ArrayList();
		List currentMembers = new ArrayList();
		List removedUsers = new ArrayList();
		List newUsers = new ArrayList();
		List changedMembers = new ArrayList();
		String userName,userDisplayName,workGroupDescription,ownerDisplayName;
		log.trace("Updating Workgroup Memebrs For The Workgroup-"+workgroupName);    
		Identity workGroupIdentity = context.getObjectByName(Identity.class,workgroupName);
		workGroupDescription = workGroupIdentity.getDescription();
		Identity ownerIdentity = context.getObjectByName(Identity.class,launcher);
		ownerDisplayName = ownerIdentity.getDisplayName();
        int existingUsersCnt=0,selectedUsersCnt=0;
        if(existingMembers!=null && !existingMembers.isEmpty()){
			existingUsersCnt = existingMembers.size();  
			log.error("Existing Members Count->"+existingUsersCnt);  
			for(String userId:existingMembers){
				Identity userIdentity = context.getObjectById(Identity.class,userId);
				userDisplayName = userIdentity.getDisplayName();
				userName = userIdentity.getName();
				log.trace("Existing Username->"+userName);
				log.trace("Existing User Displayname->"+userDisplayName);
				currentMembers.add(userName);
				if(!selectedMembers.contains(userId)){
					log.trace("Removing The Existing User->"+userDisplayName);
					userIdentity.remove(workGroupIdentity);
					context.saveObject(userIdentity);
					context.saveObject(workGroupIdentity);
					context.commitTransaction();
					removedMembers.add(userName);
					removedUsers.add(userDisplayName);
				}
            }
			changedMembers.add(removedUsers);
			Map auditData = new HashMap();
			auditData.put("Action", "Workgroup-Modification");
			auditData.put("Source", "Ascension-Workflow-ManageWorkGroups");
			auditData.put("Operation", "Remove");
			auditData.put("Workgroup Description",workGroupDescription);
			auditData.put("Members Removed", removedMembers.toString());
			auditData.put("Current Members",currentMembers.toString()); 
			auditData.put("Modified By", launcher); 

			AuditEvent auditEvent = new AuditEvent();
			auditEvent.setAction("Workgroup-Modification");
			auditEvent.setSource("Ascension-Workflow-ManageWorkGroups");
			auditEvent.setTarget("Removing Member(s)");
			auditEvent.setApplication("IIQ - WorkGroups");
			auditEvent.setAttributeValue(workgroupName);
			auditEvent.setAccountName(launcher);

			Attributes attrs = new Attributes();
			attrs.setMap(auditData);
			auditEvent.setAttributes(attrs);		
			context.saveObject(auditEvent);
			context.commitTransaction();			
        } 
        if(selectedMembers!=null && !selectedMembers.isEmpty()){
			selectedUsersCnt = selectedMembers.size();  
			log.trace("Selected Members Count->"+selectedUsersCnt);   
			for(String userId:selectedMembers){
          		Identity userIdentity = context.getObjectById(Identity.class,userId);
				userDisplayName = userIdentity.getDisplayName();
				userName = userIdentity.getName();
				log.trace("Selected Username->"+userName);
				log.trace("Selected User Displayname->"+userDisplayName);
          		if(!existingMembers.contains(userId)){
					log.trace("Adding The Selected User->"+userDisplayName);
					userIdentity.add(workGroupIdentity);
					context.saveObject(userIdentity);
					context.saveObject(workGroupIdentity);
					context.commitTransaction();
					addedMembers.add(userName);
					newUsers.add(userDisplayName);
          		}	
        	}
			changedMembers.add(newUsers);
			Map auditData = new HashMap();
			auditData.put("Action", "Workgroup-Modification");
			auditData.put("Source", "Ascension-Workflow-ManageWorkGroups");
			auditData.put("Operation", "Add");
			auditData.put("Workgroup Description",workGroupDescription);
			auditData.put("Members Added ",addedMembers.toString());
			auditData.put("Current Members",currentMembers.toString()); 
			auditData.put("Modified By", launcher); 

			AuditEvent auditEvent = new AuditEvent();
			auditEvent.setAction("Workgroup-Modification");
			auditEvent.setSource("Ascension-Workflow-ManageWorkGroups");
			auditEvent.setTarget("Adding Member(s)");
			auditEvent.setApplication("IIQ - WorkGroups");
			auditEvent.setAttributeValue(workgroupName);
			auditEvent.setAccountName(launcher);

			Attributes attrs = new Attributes();
			attrs.setMap(auditData);
			auditEvent.setAttributes(attrs);		
			context.saveObject(auditEvent);
			context.commitTransaction();	
        }  
        return changedMembers;

 	 
