							log.trace("Users Removed Summary->"+removedUsers);
							return removedUsers;

 	 
							import sailpoint.tools.Util;
							String addedUsers = Util.listToCsv(modifiedUsers.get(1));
							log.trace("Users Added Summary->"+addedUsers);
							return addedUsers;
